// Parse input: extract recordId and stage, map to video/image phases
const body = $input.first().json.body || $input.first().json;
const recordId = body.recordId || '';
const stage = parseInt(body.stage, 10);

const VIDEO_STAGE_MAP = {
  1: { videoPhase: 4, firstImagePhase: 7, lastImagePhase: 8 },
  2: { videoPhase: 3, firstImagePhase: 5, lastImagePhase: 6 },
  3: { videoPhase: 2, firstImagePhase: 3, lastImagePhase: 4 },
  4: { videoPhase: 1, firstImagePhase: 1, lastImagePhase: 2 }
};

if (!recordId) {
  return [{ json: { error: true, message: 'Missing recordId in request body' } }];
}

if (!VIDEO_STAGE_MAP[stage]) {
  return [{ json: { error: true, message: `Invalid stage: ${body.stage}. Must be 1-4.` } }];
}

const mapping = VIDEO_STAGE_MAP[stage];

return [{
  json: {
    error: false,
    recordId,
    stage,
    videoPhase: mapping.videoPhase,
    firstImagePhase: mapping.firstImagePhase,
    lastImagePhase: mapping.lastImagePhase
  }
}];

// Validate project was fetched successfully
const project = $input.first().json;
const input = $('Code — Parse Input').first().json;

if (!project || !project.id) {
  return [{ json: { error: true, stage: input.stage, message: `Failed to fetch project record ${input.recordId}. Check that the record exists in Airtable.`, recordId: input.recordId, existingLog: '' } }];
}

return [{ json: { error: false, recordId: project.id, projectName: project['Project Name'] || '', brandName: project['Brand Name'] || '', existingLog: project['Pipeline Log'] || '', canonDriveUrl: project['Canon Drive URL'] || '' } }];

// Validate fetched data and build a single Veo3 job
const input = $('Code \u2014 Parse Input').first().json;
const project = $('Code \u2014 Validate Project').first().json;

const firstFrameResp = $('HTTP \u2014 Fetch First Frame Prompt').first().json;
const lastFrameResp = $('HTTP \u2014 Fetch Last Frame Prompt').first().json;
const videoPromptResp = $('HTTP \u2014 Fetch Video Prompt').first().json;

const errors = [];

// Parse first frame
const firstFrameRecords = firstFrameResp.records || [];
if (firstFrameRecords.length === 0) {
  errors.push(`No image record found for Phase ${input.firstImagePhase} (first frame).`);
}
const firstFrame = firstFrameRecords[0];

// Parse last frame
const lastFrameRecords = lastFrameResp.records || [];
if (lastFrameRecords.length === 0) {
  errors.push(`No image record found for Phase ${input.lastImagePhase} (last frame).`);
}
const lastFrame = lastFrameRecords[0];

// Parse video prompt
const videoPromptRecords = videoPromptResp.records || [];
if (videoPromptRecords.length === 0) {
  errors.push(`No video prompt record found for Phase ${input.videoPhase}.`);
}
const videoPrompt = videoPromptRecords[0];

if (errors.length > 0) {
  return [{ json: { error: true, stage: input.stage, message: errors.join(' | '), recordId: project.recordId, existingLog: project.existingLog } }];
}

// Validate first frame has Drive File ID
const firstFrameFileId = firstFrame.fields['Drive File ID'] || '';
if (!firstFrameFileId) {
  errors.push(`First frame (Phase ${input.firstImagePhase}) missing Drive File ID.`);
}

// Validate last frame: Phase 8 uses Canon Drive URL, others use Drive File ID
let lastFrameUrl = '';
if (input.lastImagePhase === 8) {
  lastFrameUrl = project.canonDriveUrl;
  if (!lastFrameUrl) {
    errors.push('Phase 8 (canon) last frame requires Canon Drive URL on the project record, but it is missing.');
  }
} else {
  const lastFrameFileId = lastFrame.fields['Drive File ID'] || '';
  if (!lastFrameFileId) {
    errors.push(`Last frame (Phase ${input.lastImagePhase}) missing Drive File ID.`);
  } else {
    lastFrameUrl = `https://drive.google.com/uc?export=download&id=${lastFrameFileId}`;
  }
}

// Validate video prompt
const promptText = videoPrompt.fields['Prompt Text'] || '';
const genStatus = videoPrompt.fields['Generation Status'] || '';
if (!promptText) {
  errors.push(`Video prompt (Phase ${input.videoPhase}) has no Prompt Text.`);
}
if (genStatus !== 'pending' && genStatus !== 'failed') {
  errors.push(`Video prompt (Phase ${input.videoPhase}) Generation Status is '${genStatus}', expected 'pending' or 'failed'.`);
}

if (errors.length > 0) {
  return [{ json: { error: true, stage: input.stage, message: errors.join(' | '), recordId: project.recordId, existingLog: project.existingLog } }];
}

const firstFrameUrl = `https://drive.google.com/uc?export=download&id=${firstFrameFileId}`;

const callbackUrl = 'https://n8n.srv948776.hstgr.cloud/webhook/kie-callback'
  + '?type=tht_video'
  + '&table=tblWExmILcFYnW9ze'
  + '&record=' + encodeURIComponent(videoPrompt.id)
  + '&project=' + encodeURIComponent(project.recordId)
  + '&phase=' + encodeURIComponent(input.videoPhase)
  + '&stage=' + encodeURIComponent(input.stage);

return [{
  json: {
    error: false,
    prompt: promptText,
    imageUrls: [firstFrameUrl, lastFrameUrl],
    model: 'veo3',
    generationType: 'FIRST_AND_LAST_FRAMES_2_VIDEO',
    aspect_ratio: '9:16',
    callBackUrl: callbackUrl,
    videoPromptRecordId: videoPrompt.id,
    stage: input.stage,
    videoPhase: input.videoPhase,
    recordId: project.recordId,
    existingLog: project.existingLog,
    brandName: project.brandName
  }
}];

// Return success response
const job = $('Code \u2014 Validate & Build Job').first().json;
return [{
  json: {
    status: 'submitted',
    message: `Stage ${job.stage} video (Phase ${job.videoPhase}) submitted for ${job.brandName}. Callback will update record when complete.`,
    projectId: job.recordId,
    stage: job.stage,
    videoPhase: job.videoPhase
  }
}];

// Error handler: build error log and reset status
const now = new Date().toISOString().slice(0, 16).replace('T', ' ');
let errorData;
let stage = '';

// Collect error info from whichever validation failed
try { errorData = $('Code \u2014 Parse Input').first().json; if (errorData.error) { stage = errorData.stage || ''; } } catch(e) {}
if (!errorData?.error) try { errorData = $('Code \u2014 Validate Project').first().json; stage = $('Code \u2014 Parse Input').first().json.stage; } catch(e) {}
if (!errorData?.error) try { errorData = $('Code \u2014 Validate & Build Job').first().json; stage = errorData.stage; } catch(e) {}
if (!errorData) errorData = { message: 'Unknown error in Video Generator', recordId: '', existingLog: '' };

const stageNum = stage || errorData.stage || '?';
const logEntry = `[${now}] \u2717 VIDEO ERROR (Stage ${stageNum}): ${errorData.message}`;
const fullLog = errorData.existingLog ? errorData.existingLog + '\n' + logEntry : logEntry;

// Reset status to stage_N_approved so user can retry
const resetStatus = stageNum !== '?' ? `stage_${stageNum}_approved` : 'error';

return [{
  json: {
    recordId: errorData.recordId || '',
    logEntry,
    fullLog,
    status: resetStatus,
    errorMessage: errorData.message,
    stage: stageNum
  }
}];

const err = $('Code \u2014 Build Error Log').first().json;
return [{
  json: {
    status: 'error',
    stage: err.stage,
    error: err.errorMessage,
    recordId: err.recordId,
    pipelineLog: err.logEntry
  }
}];
